import type {Metadata} from "next";
import Link from "next/link";
import {ArrowLeft,Award,Check,CreditCard,LockKeyhole,Sparkles} from "lucide-react";
import {redirect} from "next/navigation";
import {openVendorBillingPortal,startVendorMembershipCheckout} from "@/app/(platform)/vendor/membership/actions";
import {formatVendorPlanPrice,VENDOR_MEMBERSHIP_PLANS,getVendorPlanByCode,normalizeVendorPlanKey} from "@/src/domain/vendor-memberships/catalog";
import {getRoleHome} from "@/src/lib/auth/routing";
import {requireUser} from "@/src/lib/auth/session";
import {createSupabaseServerClient} from "@/src/lib/supabase/server";
export const metadata:Metadata={title:"Vendor Membership"};
export default async function VendorMembershipPage({searchParams}:{searchParams:Promise<{error?:string;checkout?:string;plan?:string}>}){
 const params=await searchParams;const requestedPlan=normalizeVendorPlanKey(params.plan??"");const user=await requireUser();const org=user.memberships.find(item=>item.organizationType==="vendor"&&["owner","admin","vendor"].includes(item.role));if(!org&&requestedPlan)redirect(`/onboarding?plan=${requestedPlan}`);if(!org)redirect(getRoleHome(user));
 const supabase=await createSupabaseServerClient();const {data:current}=await supabase.from("vendor_memberships").select("status,current_period_ends_at,next_billing_at,renewal_amount_cents,amount_cents,currency,cancel_at_period_end,stripe_customer_id,vendor_membership_levels(code,name)").eq("vendor_organization_id",org.organizationId).order("created_at",{ascending:false}).limit(1).maybeSingle();
 const level=current?.vendor_membership_levels as unknown as {code:string;name:string}|null;const currentPlan=getVendorPlanByCode(level?.code??"");
 return <div><Link href="/vendor" className="inline-flex items-center text-sm font-bold text-slate-500"><ArrowLeft className="mr-2 size-4"/>Vendor overview</Link>
 {params.error?<p role="alert" className="mt-5 rounded-xl bg-rose-50 p-4 text-sm font-semibold text-rose-800">{params.error==="already_active"?"This business already has a current membership. Use Manage billing to change it safely.":params.error==="membership_required"?"Choose an active paid membership to access the vendor dashboard and property-management opportunities.":"Membership checkout is temporarily unavailable. Confirm billing configuration and try again."}</p>:null}{params.checkout==="cancelled"?<p className="mt-5 rounded-xl bg-amber-50 p-4 text-sm font-semibold text-amber-900">Checkout was canceled. No membership change was made.</p>:null}
 <div className="mt-6 grid gap-5 lg:grid-cols-[1fr_auto] lg:items-end"><div><p className="text-xs font-black uppercase tracking-[.16em] text-emerald-700">Paid vendor network</p><h1 className="mt-2 text-4xl font-semibold tracking-[-.045em] sm:text-5xl">Choose your membership.</h1><p className="mt-4 max-w-2xl text-sm leading-6 text-slate-500">Public directory access requires a paid, active membership. Plans improve visibility but never guarantee leads, jobs, or revenue.</p></div><div className="min-w-72 rounded-2xl bg-slate-950 p-5 text-white"><p className="text-[10px] font-black uppercase tracking-[.14em] text-emerald-400">Current membership</p><p className="mt-2 text-xl font-bold">{level?.name??"No active paid plan"}</p><p className="mt-1 text-xs capitalize text-slate-400">Status: {current?.status?.replaceAll("_"," ")??"inactive"}</p>{current?.next_billing_at?<p className="mt-3 text-xs text-slate-300">Next billing date: {new Date(current.next_billing_at).toLocaleDateString("en-US")}</p>:null}{current?.renewal_amount_cents?<p className="mt-1 text-xs text-slate-300">Renewal: ${(current.renewal_amount_cents/100).toFixed(2)} {current.currency}</p>:null}{current?.cancel_at_period_end?<p className="mt-2 text-xs font-bold text-amber-300">Cancels at the end of this billing period</p>:null}{current?.stripe_customer_id?<form action={openVendorBillingPortal}><button className="mt-4 inline-flex min-h-10 w-full items-center justify-center rounded-full bg-white px-4 text-xs font-black text-slate-950"><CreditCard className="mr-2 size-4"/>Manage billing</button></form>:null}</div></div>
 <section className="mt-8 grid gap-5 lg:grid-cols-3">{VENDOR_MEMBERSHIP_PLANS.filter(plan=>plan.publiclyPurchasable).map(plan=>{const active=currentPlan?.key===plan.key&&["active","trialing","past_due","complimentary","manually_granted"].includes(current?.status??"");const requested=requestedPlan===plan.key;return <article key={plan.key} className={`flex flex-col rounded-[1.6rem] border p-6 ${plan.key==="preferred"?"border-emerald-400 bg-slate-950 text-white shadow-xl":"border-slate-200 bg-white"} ${requested?"ring-4 ring-emerald-200":""}`}><div className="flex items-center justify-between"><span className={`grid size-10 place-items-center rounded-xl ${plan.key==="preferred"?"bg-white/10 text-emerald-400":"bg-amber-50 text-amber-700"}`}>{plan.key==="founding_partner"?<Award className="size-5"/>:<Sparkles className="size-5"/>}</span>{plan.capacity?<span className="rounded-full bg-amber-100 px-3 py-1 text-[10px] font-black text-amber-900">Limited availability</span>:null}</div><h2 className="mt-6 text-xl font-bold">{plan.name}</h2><p className="mt-4 text-4xl font-semibold">{formatVendorPlanPrice(plan)}</p><p className="mt-5 min-h-18 text-sm leading-6 opacity-75">{plan.description}</p>{plan.key==="founding_partner"?<p className="mb-5 text-xs font-semibold opacity-75">The one-time charge is collected immediately and does not renew automatically.</p>:null}<ul className="mt-6 space-y-3 border-t border-current/10 pt-5">{plan.features.map(feature=><li key={feature} className="flex gap-2 text-xs"><Check className="size-4 shrink-0 text-emerald-500"/>{feature}</li>)}</ul><div className="mt-auto pt-7">{active?<span className="inline-flex min-h-11 w-full items-center justify-center rounded-full bg-emerald-50 text-xs font-black text-emerald-800"><LockKeyhole className="mr-2 size-4"/>Current plan</span>:<form action={startVendorMembershipCheckout}><input type="hidden" name="plan" value={plan.key}/><button className={`min-h-11 w-full rounded-full px-4 text-xs font-black ${plan.key==="preferred"?"bg-emerald-400 text-emerald-950":"bg-slate-950 text-white"}`}>{plan.key==="founding_partner"?"Become a Founding Partner":plan.key==="network"?"Join the Network":"Become a Preferred Vendor"}</button></form>}</div></article>})}</section>
 <p className="mt-6 text-xs leading-5 text-slate-500">The canonical Founding Partner offer is a one-time Stripe payment. Network and Preferred Vendor plans remain recurring subscriptions.</p></div>;
}
